import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Dumbbell, User, ArrowLeft, ChevronUp } from 'lucide-react';
import { AppProvider } from './contexts/AppContext';
import { WorkoutProvider, useWorkout } from './contexts/WorkoutContext';
import WorkoutTab from './components/WorkoutTab';
import HistoryTab from './components/HistoryTab';
import LiveWorkout from './components/LiveWorkout';
import { fmtTime } from './utils/format';
import './index.css';

export default function GymApp() {
  return (
    <AppProvider>
      <WorkoutProvider>
        <GymAppInner />
      </WorkoutProvider>
    </AppProvider>
  );
}

// true on devices that have a real pointer (desktop/laptop)
const hasHover = window.matchMedia('(hover: hover)').matches;

function GymAppInner() {
  const navigate = useNavigate();
  const { session, elapsed, isMinimized, expand } = useWorkout();
  const [tab, setTab] = useState('workout');
  // On touch devices bar is always visible; on desktop show only near top
  const [barVisible, setBarVisible] = useState(!hasHover);

  useEffect(() => {
    if (!hasHover) return;
    const onMove = (e) => setBarVisible(e.clientY < 64);
    window.addEventListener('mousemove', onMove);
    return () => window.removeEventListener('mousemove', onMove);
  }, []);

  const TABS = [
    { id: 'workout', label: 'Workout', icon: Dumbbell },
    { id: 'history', label: 'History', icon: User },
  ];

  return (
    <div className="app">
      {/* Top bar — hidden during active session */}
      {!session && (
        <div className={`top-bar${barVisible ? ' top-bar--visible' : ''}`}>
          <button className="top-bar-back" onClick={() => navigate('/')}>
            <ArrowLeft size={14} />
            <span>Apps</span>
          </button>
        </div>
      )}

      {/* Tab content — use display:none trick to preserve state across tab switches */}
      <div style={{ display: tab === 'workout' ? 'contents' : 'none' }}><WorkoutTab active={tab === 'workout'} /></div>
      <div style={{ display: tab === 'history' ? 'contents' : 'none' }}><HistoryTab active={tab === 'history'} /></div>

      {/* Bottom nav — always visible */}
      <nav className="bottom-nav">
        {TABS.map(({ id, label, icon: Icon }) => (
          <button
            key={id}
            className={`nav-btn${tab === id ? ' active' : ''}`}
            onClick={() => setTab(id)}
          >
            <Icon size={22} />
            <span>{label}</span>
          </button>
        ))}
      </nav>

      {/* Live workout overlay */}
      {session && !isMinimized && <LiveWorkout onFinished={() => setTab('history')} />}

      {/* Minimized workout bar — shown when workout is active but collapsed */}
      {session && isMinimized && (
        <div
          onClick={expand}
          style={{
            position: 'fixed', bottom: 'calc(72px + env(safe-area-inset-bottom, 0px))', left: 12, right: 12, zIndex: 200,
            background: 'var(--bg2)', border: '1px solid var(--border)',
            borderRadius: 16, padding: '14px 18px',
            display: 'flex', alignItems: 'center', gap: 12,
            cursor: 'pointer', boxShadow: '0 4px 20px rgba(0,0,0,0.4)',
          }}
        >
          <ChevronUp size={18} color="var(--accent)" />
          <span style={{ flex: 1, fontWeight: 600, fontSize: 15, color: 'var(--text)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
            {session.title || 'Quick Workout'}
          </span>
          <span style={{ fontSize: 14, fontWeight: 700, color: 'var(--accent)', fontVariantNumeric: 'tabular-nums' }}>
            {fmtTime(elapsed)}
          </span>
        </div>
      )}
    </div>
  );
}
