// ── Volume formatting ──────────────────────────────────────────────────────────
function fmtVolLocal(kg) {
  if (!kg || kg === 0) return '—';
  if (kg >= 1000) return `${(kg / 1000).toFixed(1)}k kg`;
  return `${Math.round(kg)} kg`;
}

