// ── Helper functions ───────────────────────────────────────────────────────────
function getPeriodCutoff(period) {
  const d = new Date(); d.setHours(0, 0, 0, 0);
  if (period === '3m') { d.setMonth(d.getMonth() - 3); return d; }
  if (period === '1y') { d.setFullYear(d.getFullYear() - 1); return d; }
  return null;
}

function aggregateBarData(sessions, period) {
  const cutoff = getPeriodCutoff(period);
  const filtered = cutoff ? sessions.filter(s => new Date(s.date) >= cutoff) : sessions;
  if (!filtered.length) return [];

  const useWeeks = period === '3m';
  const buckets = new Map();
  for (const s of filtered) {
    const d = new Date(s.date);
    let key, label;
    if (useWeeks) {
      const sun = new Date(d); sun.setDate(d.getDate() - d.getDay()); sun.setHours(0, 0, 0, 0);
      key = sun.toLocaleDateString('en-CA');
      label = `${sun.getDate()} ${MONTHS_SHORT[sun.getMonth()]}`;
    } else {
      key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      label = `${MONTHS_SHORT[d.getMonth()]} ${String(d.getFullYear()).slice(2)}`;
    }
    if (!buckets.has(key)) buckets.set(key, { label, key, duration: 0, volume: 0, reps: 0 });
    const b = buckets.get(key);
    b.duration += (s.duration || 0);
    b.volume += calcVolume(s.exercises || []);
    for (const ex of s.exercises || []) {
      for (const set of ex.sets || []) {
        if (set.completed) b.reps += (set.reps || 0);
      }
    }
  }
  return Array.from(buckets.values()).sort((a, b) => a.key.localeCompare(b.key));
}

function getPeriodSummary(sessions, period) {
  const cutoff = getPeriodCutoff(period);
  const filtered = cutoff ? sessions.filter(s => new Date(s.date) >= cutoff) : sessions;
  const totalMin = filtered.reduce((a, s) => a + (s.duration || 0), 0);
  return { count: filtered.length, totalMin };
}

function getBodyPartSets(sessions, cutoff) {
  const filtered = cutoff ? sessions.filter(s => new Date(s.date) >= cutoff) : sessions;
  const counts = {};
  for (const s of filtered) {
    for (const ex of s.exercises || []) {
      const bp = (ex.bodyPart || getExerciseByName(ex.name)?.bodyPart || '').toLowerCase();
      if (bp) {
        const n = (ex.sets || []).filter(set => set.completed).length;
        counts[bp] = (counts[bp] || 0) + n;
      }
    }
  }
  return counts;
}

function aggregateSetCountData(sessions, period) {
  const cutoff = getPeriodCutoff(period);
  const filtered = cutoff ? sessions.filter(s => new Date(s.date) >= cutoff) : sessions;
  const useWeeks = period !== '1y' && period !== 'all';

  const buckets = new Map();
  const allMuscles = new Set();
  for (const s of filtered) {
    const d = new Date(s.date);
    let key, label;
    if (useWeeks) {
      const sun = new Date(d); sun.setDate(d.getDate() - d.getDay()); sun.setHours(0, 0, 0, 0);
      key = sun.toLocaleDateString('en-CA');
      label = `${sun.getDate()} ${MONTHS_SHORT[sun.getMonth()]}`;
    } else {
      key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      label = MONTHS_SHORT[d.getMonth()];
    }
    if (!buckets.has(key)) buckets.set(key, { label, key });
    const b = buckets.get(key);
    for (const ex of s.exercises || []) {
      const bp = (ex.bodyPart || getExerciseByName(ex.name)?.bodyPart || '').toLowerCase();
      if (!bp) continue;
      const n = (ex.sets || []).filter(set => set.completed).length;
      b[bp] = (b[bp] || 0) + n;
      allMuscles.add(bp);
    }
  }
  const data = Array.from(buckets.values()).sort((a, b) => a.key.localeCompare(b.key));
  return { lines: Array.from(allMuscles), data };
}

function getRadarData(sessions, period) {
  const cutoff = getPeriodCutoff(period || '3m');
  const now = new Date();
  const periodLen = cutoff ? (now - cutoff) : null;
  const prevCutoff = periodLen ? new Date(cutoff - periodLen) : null;

  function groupSets(sess) {
    const bp = {};
    for (const s of sess) {
      for (const ex of s.exercises || []) {
        const p = (ex.bodyPart || getExerciseByName(ex.name)?.bodyPart || '').toLowerCase();
        const n = (ex.sets || []).filter(set => set.completed).length;
        bp[p] = (bp[p] || 0) + n;
      }
    }
    return bp;
  }

  const currSess = cutoff ? sessions.filter(s => new Date(s.date) >= cutoff) : sessions;
  const prevSess = (cutoff && prevCutoff)
    ? sessions.filter(s => { const d = new Date(s.date); return d >= prevCutoff && d < cutoff; })
    : [];

  const currBP = groupSets(currSess);
  const prevBP = groupSets(prevSess);

  const maxVal = Math.max(1,
    ...RADAR_GROUPS.map(g => Math.max(
      g.keys.reduce((a, k) => a + (currBP[k] || 0), 0),
      g.keys.reduce((a, k) => a + (prevBP[k] || 0), 0),
    ))
  );

  return RADAR_GROUPS.map(g => ({
    group: g.label,
    current:  g.keys.reduce((a, k) => a + (currBP[k] || 0), 0) / maxVal * 100,
    previous: g.keys.reduce((a, k) => a + (prevBP[k] || 0), 0) / maxVal * 100,
  }));
}

// ── Week helpers ───────────────────────────────────────────────────────────────
function weekStartFor(offset) {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const sun = new Date(today);
  sun.setDate(today.getDate() - today.getDay() + offset * 7);
  return sun;
}

function formatWeekRange(start, end) {
  const s = String(start.getDate()).padStart(2, '0');
  const e = String(end.getDate()).padStart(2, '0');
  if (start.getMonth() === end.getMonth()) {
    return `${s}-${e} ${MONTHS_FULL[start.getMonth()]} ${start.getFullYear()}`;
  }
  const sm = MONTHS_FULL[start.getMonth()].slice(0, 3);
  const em = MONTHS_FULL[end.getMonth()].slice(0, 3);
  return `${s} ${sm} – ${e} ${em} ${end.getFullYear()}`;
}

// ── ActivityChart ─────────────────────────────────────────────────────────────
function ActivityChart({ sessions }) {
  const [period, setPeriod] = useState('3m');
  const [metric, setMetric] = useState('duration');

  const barData = useMemo(() => aggregateBarData(sessions, period), [sessions, period]);
  const summary = useMemo(() => getPeriodSummary(sessions, period), [sessions, period]);

  const fmtBarVal = (v) => {
    if (metric === 'duration') return v >= 3600 ? `${(v / 3600).toFixed(1)}h` : `${Math.round(v / 60)}m`;
    if (metric === 'volume')   return v >= 1000 ? `${(v / 1000).toFixed(1)}k` : `${Math.round(v)}`;
    return String(v);
  };

  const summaryText = () => {
    const mins = summary.totalMin;
    const hrs = mins >= 3600 ? `${(mins / 3600).toFixed(1)} hrs` : `${Math.round(mins / 60)} min`;
    return `${summary.count} workouts · ${hrs} total`;
  };

  return (
    <div style={{ margin: '0 16px 16px', background: 'var(--bg2)', borderRadius: 14, border: '1px solid var(--border)', padding: '14px 16px 12px' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
        <span style={{ fontSize: 13, color: 'var(--text3)' }}>{summaryText()}</span>
        <div style={{ display: 'flex', gap: 4 }}>
          {PERIOD_OPTS.map(o => (
            <button key={o.id} onClick={() => setPeriod(o.id)} style={{
              padding: '4px 10px', borderRadius: 8, border: 'none', cursor: 'pointer', fontSize: 12, fontWeight: 600,
              background: period === o.id ? 'var(--accent)' : 'var(--bg3)',
              color: period === o.id ? '#fff' : 'var(--text2)',
            }}>{o.label}</button>
          ))}
        </div>
      </div>

      <div style={{ display: 'flex', marginBottom: 12, borderBottom: '1px solid var(--border)' }}>
        {METRIC_OPTS.map(o => (
          <button key={o.id} onClick={() => setMetric(o.id)} style={{
            flex: 1, padding: '7px 0', background: 'none', border: 'none', cursor: 'pointer',
            fontSize: 13, fontWeight: 600,
            color: metric === o.id ? 'var(--accent)' : 'var(--text3)',
            borderBottom: metric === o.id ? '2px solid var(--accent)' : '2px solid transparent',
          }}>{o.label}</button>
        ))}
      </div>

      {barData.length === 0 ? (
        <div style={{ height: 120, display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text3)', fontSize: 13 }}>
          No data for this period
        </div>
      ) : (
        <ResponsiveContainer width="100%" height={120}>
          <BarChart data={barData} barSize={barData.length > 20 ? 4 : 8} margin={{ top: 4, right: 0, left: -30, bottom: 0 }}>
            <XAxis dataKey="label" tick={{ fontSize: 10, fill: 'var(--text3)' }} interval="preserveStartEnd" axisLine={false} tickLine={false} />
            <YAxis tick={{ fontSize: 10, fill: 'var(--text3)' }} tickFormatter={fmtBarVal} axisLine={false} tickLine={false} />
            <Tooltip
              formatter={(v) => [fmtBarVal(v), metric]}
              contentStyle={{ background: 'var(--bg3)', border: '1px solid var(--border)', borderRadius: 8, fontSize: 12 }}
              labelStyle={{ color: 'var(--text2)' }}
            />
            <Bar dataKey={metric} fill="var(--accent)" radius={[3, 3, 0, 0]} />
          </BarChart>
        </ResponsiveContainer>
      )}
    </div>
  );
}

// ── BodyGraph (used in StatisticsView) ────────────────────────────────────────
function BodyGraph({ sessions, onTap }) {
  const days = useMemo(() => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date(today);
      d.setDate(today.getDate() - (6 - i));
      return d;
    });
  }, []);

  const sessionDateKeys = useMemo(() => {
    const set = new Set();
    for (const s of sessions) set.add(new Date(s.date).toLocaleDateString('en-CA'));
    return set;
  }, [sessions]);

  const muscleIntensities = useMemo(() => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const cutoff = new Date(today);
    cutoff.setDate(today.getDate() - 6);

    const counts = {};
    for (const s of sessions) {
      if (new Date(s.date) < cutoff) continue;
      for (const ex of s.exercises || []) {
        const bp = (ex.bodyPart || getExerciseByName(ex.name)?.bodyPart || '').toLowerCase();
        const slugs = BP_MAP[bp];
        if (slugs) {
          const n = (ex.sets || []).filter(set => set.completed).length;
          slugs.forEach(slug => { counts[slug] = (counts[slug] || 0) + n; });
        }
      }
    }
    const result = {};
    for (const [k, v] of Object.entries(counts)) result[k] = v <= 0 ? 0 : Math.min(0.2 + (v - 1) / 19 * 0.8, 1);
    return result;
  }, [sessions]);

  return (
    <div onClick={onTap} style={{ margin: '0 16px 16px', background: 'var(--bg2)', borderRadius: 14, border: '1px solid var(--border)', overflow: 'hidden', cursor: 'pointer' }}>
      <div style={{ padding: '14px 16px 10px' }}>
        <span style={{ fontSize: 15, fontWeight: 700, color: 'var(--text)' }}>Last 7 days</span>
      </div>

      <div style={{ display: 'flex', gap: 5, padding: '0 12px 14px' }}>
        {days.map((d, i) => {
          const key = d.toLocaleDateString('en-CA');
          const hasWorkout = sessionDateKeys.has(key);
          const isToday = i === 6;
          return (
            <div key={i} style={{
              flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center',
              padding: '7px 2px 5px',
              background: isToday ? 'var(--bg3)' : 'var(--bg)',
              borderRadius: 8,
              border: `1px solid ${isToday ? 'var(--accent)' : 'var(--border)'}`,
              gap: 2,
            }}>
              <span style={{ fontSize: 10, fontWeight: 600, color: isToday ? 'var(--accent)' : 'var(--text3)', letterSpacing: '0.03em' }}>
                {DAY_ABBR[d.getDay()]}
              </span>
              <span style={{ fontSize: 13, fontWeight: isToday ? 700 : 400, color: isToday ? 'var(--text)' : 'var(--text2)' }}>
                {d.getDate()}
              </span>
              <div style={{ width: 5, height: 5, borderRadius: '50%', background: hasWorkout ? 'var(--accent)' : 'transparent' }} />
            </div>
          );
        })}
      </div>

      <div style={{ padding: '0 12px 16px' }}>
        <MuscleDiagram intensities={muscleIntensities} />
      </div>
    </div>
  );
}

// ── BodyDistributionView ──────────────────────────────────────────────────────
function BodyDistributionView({ sessions, onClose }) {
  const [weekOffset, setWeekOffset] = useState(0);

  const weekStart = useMemo(() => weekStartFor(weekOffset), [weekOffset]);
  const weekEnd   = useMemo(() => { const d = new Date(weekStart); d.setDate(d.getDate() + 6); return d; }, [weekStart]);

  const days = useMemo(() => Array.from({ length: 7 }, (_, i) => {
    const d = new Date(weekStart); d.setDate(weekStart.getDate() + i); return d;
  }), [weekStart]);

  const weekSessions = useMemo(() => {
    const sk = weekStart.toLocaleDateString('en-CA');
    const ek = weekEnd.toLocaleDateString('en-CA');
    return sessions.filter(s => {
      const k = new Date(s.date).toLocaleDateString('en-CA');
      return k >= sk && k <= ek;
    });
  }, [sessions, weekStart, weekEnd]);

  const sessionDateKeys = useMemo(() => {
    const set = new Set();
    for (const s of weekSessions) set.add(new Date(s.date).toLocaleDateString('en-CA'));
    return set;
  }, [weekSessions]);

  const bodyPartCounts = useMemo(() => {
    const counts = {};
    for (const s of weekSessions) {
      for (const ex of s.exercises || []) {
        const bp = (ex.bodyPart || getExerciseByName(ex.name)?.bodyPart || '').toLowerCase();
        if (BP_MAP[bp]) {
          const n = (ex.sets || []).filter(set => set.completed).length;
          counts[bp] = (counts[bp] || 0) + n;
        }
      }
    }
    return counts;
  }, [weekSessions]);

  const intensities = useMemo(() => {
    const counts = {};
    for (const s of weekSessions) {
      for (const ex of s.exercises || []) {
        const bp = (ex.bodyPart || getExerciseByName(ex.name)?.bodyPart || '').toLowerCase();
        const slugs = BP_MAP[bp];
        if (slugs) {
          const n = (ex.sets || []).filter(set => set.completed).length;
          slugs.forEach(slug => { counts[slug] = (counts[slug] || 0) + n; });
        }
      }
    }
    const result = {};
    for (const [k, v] of Object.entries(counts)) result[k] = v <= 0 ? 0 : Math.min(0.2 + (v - 1) / 19 * 0.8, 1);
    return result;
  }, [weekSessions]);

  const totalSets = useMemo(() => Object.values(bodyPartCounts).reduce((a, b) => a + b, 0), [bodyPartCounts]);
  const todayKey  = new Date().toLocaleDateString('en-CA');

  return (
    <div style={{ position: 'fixed', inset: 0, zIndex: 170, background: 'var(--bg)', display: 'flex', flexDirection: 'column' }}>
      <div style={{ display: 'flex', alignItems: 'center', padding: '54px 16px 12px', borderBottom: '1px solid var(--border)', flexShrink: 0 }}>
        <button onClick={onClose} style={{ background: 'none', border: 'none', color: 'var(--text)', cursor: 'pointer', display: 'flex', alignItems: 'center', padding: '4px 8px 4px 0' }}>
          <ArrowLeft size={22} />
        </button>
        <span style={{ flex: 1, textAlign: 'center', fontSize: 17, fontWeight: 700, color: 'var(--text)' }}>Body distribution</span>
        <div style={{ width: 30 }} />
      </div>

      <div style={{ flex: 1, overflowY: 'auto', paddingBottom: 40 }}>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '14px 12px 10px' }}>
          <button onClick={() => setWeekOffset(o => o - 1)} style={{ background: 'none', border: 'none', color: 'var(--text)', cursor: 'pointer', padding: 6, display: 'flex' }}>
            <ChevronLeft size={20} />
          </button>
          <span style={{ fontSize: 15, fontWeight: 600, color: 'var(--text)' }}>{formatWeekRange(weekStart, weekEnd)}</span>
          <button onClick={() => setWeekOffset(o => o + 1)} disabled={weekOffset >= 0} style={{ background: 'none', border: 'none', color: weekOffset >= 0 ? 'var(--border)' : 'var(--text)', cursor: weekOffset >= 0 ? 'default' : 'pointer', padding: 6, display: 'flex' }}>
            <ChevronRight size={20} />
          </button>
        </div>

        <div style={{ display: 'flex', gap: 4, padding: '0 16px 20px' }}>
          {days.map((d, i) => {
            const key = d.toLocaleDateString('en-CA');
            const hasWorkout = sessionDateKeys.has(key);
            const isToday = key === todayKey;
            return (
              <div key={i} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 4 }}>
                <span style={{ fontSize: 11, fontWeight: 600, color: 'var(--text3)' }}>{DAY_ABBR[d.getDay()]}</span>
                <div style={{
                  width: 30, height: 30, borderRadius: '50%',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  background: hasWorkout ? 'var(--accent)' : 'transparent',
                  border: isToday && !hasWorkout ? '1.5px solid var(--text3)' : 'none',
                }}>
                  <span style={{ fontSize: 13, fontWeight: hasWorkout ? 700 : 400, color: hasWorkout ? '#fff' : isToday ? 'var(--text)' : 'var(--text2)' }}>
                    {d.getDate()}
                  </span>
                </div>
              </div>
            );
          })}
        </div>

        <div style={{ padding: '0 16px 28px' }}>
          <MuscleDiagram intensities={intensities} size={165} />
        </div>

        <div style={{ borderTop: '1px solid var(--border)' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', padding: '10px 20px', borderBottom: '1px solid var(--border)' }}>
            <span style={{ fontSize: 12, fontWeight: 700, color: 'var(--text3)', textTransform: 'uppercase', letterSpacing: '0.6px' }}>Muscle</span>
            <span style={{ fontSize: 12, fontWeight: 700, color: 'var(--text3)', textTransform: 'uppercase', letterSpacing: '0.6px' }}>Sets</span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', padding: '15px 20px', borderBottom: '1px solid var(--border)' }}>
            <span style={{ fontSize: 15, fontWeight: 600, color: 'var(--text)' }}>Total</span>
            <span style={{ fontSize: 15, fontWeight: 600, color: 'var(--text)' }}>{totalSets}</span>
          </div>
          {MUSCLE_LIST.map(({ label, key }) => {
            const count = bodyPartCounts[key] || 0;
            return (
              <div key={key} style={{ display: 'flex', justifyContent: 'space-between', padding: '15px 20px', borderBottom: '1px solid var(--border)' }}>
                <span style={{ fontSize: 15, color: 'var(--text)' }}>{label}</span>
                <span style={{ fontSize: 15, color: count > 0 ? 'var(--text)' : 'var(--text3)' }}>{count}</span>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

